# First failing test: Can parse semantic version from package.json
Describe "Semantic Version Bumper" {
    BeforeAll {
        # Source the script we're testing
        . $PSScriptRoot/semantic-version-bumper.ps1
    }

    Context "Parse Version" {
        It "should parse version from package.json" {
            # Arrange
            $testDir = Join-Path $env:TEMP "svb-test-$(Get-Random)"
            New-Item -ItemType Directory -Path $testDir -Force | Out-Null

            $packageJson = @{
                version = "1.0.0"
            } | ConvertTo-Json

            Set-Content -Path (Join-Path $testDir "package.json") -Value $packageJson

            # Act
            $version = Get-CurrentVersion -Path (Join-Path $testDir "package.json")

            # Assert
            $version | Should -Be "1.0.0"

            # Cleanup
            Remove-Item -Path $testDir -Recurse -Force
        }
    }
}

# Run the tests
Invoke-Pester -Path $PSScriptRoot/semantic-version-bumper.tests.ps1 -Verbose

