# Semantic Version Bumper
# Parses version, determines next version based on conventional commits, updates files, generates changelog

function Get-CurrentVersion {
    param(
        [string]$Path
    )

    if (-not (Test-Path $Path)) {
        throw "File not found: $Path"
    }

    $content = Get-Content -Path $Path -Raw | ConvertFrom-Json
    return $content.version
}

function Get-NextVersion {
    param(
        [string]$CurrentVersion,
        [string[]]$Commits
    )

    # Parse current version
    $versionParts = $CurrentVersion -split '\.'
    [int]$major = $versionParts[0]
    [int]$minor = $versionParts[1]
    [int]$patch = $versionParts[2]

    # Determine bump type from commits
    $bumpType = "none"
    foreach ($commit in $Commits) {
        if ($commit -match "^breaking|BREAKING\s+CHANGE") {
            $bumpType = "major"
            break
        }
    }

    if ($bumpType -ne "major") {
        foreach ($commit in $Commits) {
            if ($commit -match "^feat") {
                $bumpType = "minor"
                break
            }
        }
    }

    if ($bumpType -eq "none") {
        foreach ($commit in $Commits) {
            if ($commit -match "^fix") {
                $bumpType = "patch"
                break
            }
        }
    }

    # Apply bump
    switch ($bumpType) {
        "major" {
            $major++
            $minor = 0
            $patch = 0
        }
        "minor" {
            $minor++
            $patch = 0
        }
        "patch" {
            $patch++
        }
    }

    return "$major.$minor.$patch"
}

