    if ($workflowContent -match "^name:") {
        Write-Host "  ✓ Has 'name' field"
        $passed++
    } else {
        Write-Host "  ✗ Missing 'name' field"
        $failed++
    }

    if ($workflowContent -match "^on:") {
        Write-Host "  ✓ Has 'on' trigger"
        $passed++
    } else {
